// LINEメッセージを受信して必要な情報を抽出
const body = $input.item.json.body;
const events = body.events || [];

if (events.length === 0) {
  return [{ json: { skip: true } }];
}

const event = events[0];
const userId = event.source?.userId || '';
const messageText = event.message?.text || '';
const replyToken = event.replyToken || '';

return [{
  json: {
    userId,
    messageText,
    replyToken,
    eventType: event.type
  }
}];

// 社員IDマッピングテーブル
// 新しい社員を追加する場合はここに追記してください
const employeeMap = [
  {
    userId: 'Uc1e1e958fb952752c3d34628a17585a1',
    employeeName: '野添優',
    fileName: '稼働表_野添優.xlsx'
  }
  // 他の社員を追加する場合はここに追記
  // 例:
  // {
  //   userId: 'U xxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxxx',
  //   employeeName: '氏名',
  //   fileName: '稼働表_氏名.xlsx'
  // }
];

const userId = $input.item.json.userId;
const employee = employeeMap.find(e => e.userId === userId);

if (!employee) {
  return [{
    json: {
      valid: false,
      errorMessage: '登録されていないLINEアカウント',
      userId
    }
  }];
}

return [{
  json: {
    valid: true,
    userId: employee.userId,
    employeeName: employee.employeeName,
    fileName: employee.fileName,
    replyToken: $input.item.json.replyToken,
    messageText: $input.item.json.messageText
  }
}];

// エラーメッセージを送信するためのペイロードを作成
const errorMessage = $input.item.json.errorMessage || 'エラーが発生しました';

return [{
  json: {
    replyToken: $input.item.json.replyToken,
    messages: [
      {
        type: 'text',
        text: `エラー: ${errorMessage}`
      }
    ]
  }
}];

// 勤怠処理のメインロジック
const employeeName = $input.item.json.employeeName;
const fileName = $input.item.json.fileName;
const messageText = $input.item.json.messageText;

// メッセージ内容に基づいて処理を分岐
let action = 'unknown';
if (messageText.includes('出勤') || messageText.includes('おはよう')) {
  action = 'clockIn';
} else if (messageText.includes('退勤') || messageText.includes('お疲れ')) {
  action = 'clockOut';
}

return [{
  json: {
    employeeName,
    fileName,
    action,
    replyToken: $input.item.json.replyToken,
    timestamp: new Date().toISOString()
  }
}];
